previewCss:
.darma-loader-loaders-css-33 {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 7px;
      min-width: 57px;
      min-height: 24px;
    }
    .darma-loader-loaders-css-33 i {
      display: block;
      width: 12px;
      height: 12px;
      border-radius: 50%;
      background: var(--loader-color, #f59e0b);
      animation: darma-loader-loaders-css-33-dotPulse 0.73s ease-in-out infinite;
    }
    .darma-loader-loaders-css-33 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loaders-css-33 i:nth-child(2) { animation-delay: 0.12s; }
.darma-loader-loaders-css-33 i:nth-child(3) { animation-delay: 0.24s; }
    @keyframes darma-loader-loaders-css-33-dotPulse { 0%, 80%, 100% { opacity: .25; transform: scale(.7); } 40% { opacity: 1; transform: scale(1); } }

